channel = []

def send(message):
    channel.append(message)

def recv():
    message = channel[0]
    del channel[0]
    return message

def produce():
    for i in range(3):
        send(i)
    send(None)  # done signal

def consume():
    received = []
    while True:
        item = recv()
        if item is None:
            return received
        received.append(item)

produce()
result = consume()
print('consumed:', result)
print('channel left over:', channel)
